const bearer = $input.first().json.access_token;
const hoje = new Date(Date.now() - 3 * 60 * 60 * 1000);
const dd = String(hoje.getUTCDate()).padStart(2, '0');
const mm = String(hoje.getUTCMonth() + 1).padStart(2, '0');
const yyyy = hoje.getUTCFullYear();
return [{ json: { bearer, hoje: dd + '/' + mm + '/' + yyyy } }];

const assuntosIgnorados = [
  'PTE - Pedido de Protocolo Eletrônico',
  'PRE - Pedido de Renúncia',
  'SOLIC - Solicitação CJ',
];
const rows = ($input.first().json.rows || [])
  .filter(r => r.status !== 'Concluído')
  .filter(r => !assuntosIgnorados.some(a => (r.assunto || '').startsWith(a)));
if (rows.length === 0) return [];
console.log('Atividades do dia: ' + rows.length);
return rows.map(r => ({ json: r }));

const processadosIds = new Set(
  $input.all()
    .map(r => r.json.source_id)
    .filter(id => id !== undefined && id !== null && id !== '')
    .map(String)
);
const atividades = $('Extrai Atividades').all();
const novas = atividades.filter(a => a.json.id !== undefined && !processadosIds.has(String(a.json.id)));
if (novas.length === 0) return [];
console.log('Atividades novas: ' + novas.length + ' de ' + atividades.length + ' do dia');
return novas;

